import React, { ReactNode } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, PieChart, Pie, Cell } from 'recharts';

interface GlassCardProps {
  children: ReactNode;
  className?: string;
  title?: string;
  action?: ReactNode;
}

export const GlassCard: React.FC<GlassCardProps> = ({ children, className = '', title, action }) => {
  return (
    <div className={`
      relative overflow-hidden
      bg-[#141414]/80 backdrop-blur-xl 
      border border-white/5 
      rounded-2xl 
      shadow-lg
      transition-all duration-300
      hover:border-brand-yellow/30 hover:shadow-glow-sm
      ${className}
    `}>
      {(title || action) && (
        <div className="flex justify-between items-center p-6 border-b border-white/5">
          {title && <h3 className="text-lg font-display font-semibold text-gray-100 tracking-wide">{title}</h3>}
          {action && <div>{action}</div>}
        </div>
      )}
      <div className="p-6">
        {children}
      </div>
    </div>
  );
};

export const StatCard: React.FC<{ label: string; value: string; trend?: string; icon?: ReactNode, positive?: boolean }> = ({ label, value, trend, icon, positive }) => (
  <GlassCard className="flex flex-col justify-between h-32">
    <div className="flex justify-between items-start">
      <span className="text-gray-400 text-sm font-medium">{label}</span>
      {icon && <div className="text-brand-yellow/80">{icon}</div>}
    </div>
    <div>
      <div className="text-3xl font-display font-bold text-white mb-1">{value}</div>
      {trend && (
        <span className={`text-xs px-2 py-0.5 rounded-full ${positive ? 'bg-green-500/10 text-green-400' : 'bg-red-500/10 text-red-400'}`}>
          {trend}
        </span>
      )}
    </div>
  </GlassCard>
);

export const PrimaryButton: React.FC<React.ButtonHTMLAttributes<HTMLButtonElement>> = ({ children, className = '', ...props }) => (
  <button 
    className={`
      bg-gradient-to-r from-brand-yellow to-brand-yellowDark
      text-black font-semibold font-display
      px-6 py-2.5 rounded-xl
      shadow-lg shadow-brand-yellow/20
      hover:shadow-glow hover:scale-[1.02]
      active:scale-95
      transition-all duration-200
      disabled:opacity-50 disabled:cursor-not-allowed
      ${className}
    `}
    {...props}
  >
    {children}
  </button>
);

export const ThemeAreaChart: React.FC<{ data: any[], dataKey: string, height?: number, color?: string }> = ({ data, dataKey, height = 300, color = '#FF7F27' }) => (
  <ResponsiveContainer width="100%" height={height}>
    <AreaChart data={data}>
      <defs>
        <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="5%" stopColor={color} stopOpacity={0.3}/>
          <stop offset="95%" stopColor={color} stopOpacity={0}/>
        </linearGradient>
      </defs>
      <CartesianGrid strokeDasharray="3 3" stroke="#333" vertical={false} />
      <XAxis dataKey="name" stroke="#666" tick={{fill: '#666', fontSize: 12}} tickLine={false} axisLine={false} />
      <YAxis stroke="#666" tick={{fill: '#666', fontSize: 12}} tickLine={false} axisLine={false} />
      <Tooltip 
        contentStyle={{ backgroundColor: '#1a1a1a', border: '1px solid #333', borderRadius: '8px' }}
        itemStyle={{ color: '#fff' }}
      />
      <Area type="monotone" dataKey={dataKey} stroke={color} strokeWidth={3} fillOpacity={1} fill={`url(#color${dataKey})`} />
    </AreaChart>
  </ResponsiveContainer>
);

const COLORS = ['#FF7F27', '#E0E0E0', '#444444', '#1A1A1A'];

export const ThemePieChart: React.FC<{ data: any[] }> = ({ data }) => (
  <ResponsiveContainer width="100%" height={300}>
    <PieChart>
      <Pie
        data={data}
        cx="50%"
        cy="50%"
        innerRadius={60}
        outerRadius={80}
        fill="#8884d8"
        paddingAngle={5}
        dataKey="value"
      >
        {data.map((entry, index) => (
          <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
        ))}
      </Pie>
      <Tooltip 
         contentStyle={{ backgroundColor: '#1a1a1a', border: '1px solid #333', borderRadius: '8px' }}
         itemStyle={{ color: '#fff' }}
      />
    </PieChart>
  </ResponsiveContainer>
);

export const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  let colorClass = 'bg-gray-800 text-gray-300';
  if (status === 'Active' || status === 'Resolved' || status === 'Open') colorClass = 'bg-green-500/10 text-green-400 border border-green-500/20';
  if (status === 'Maintenance' || status === 'In Progress') colorClass = 'bg-brand-yellow/10 text-brand-yellow border border-brand-yellow/20';
  if (status === 'Critical' || status === 'Low Battery') colorClass = 'bg-red-500/10 text-red-400 border border-red-500/20';

  return (
    <span className={`px-2.5 py-1 rounded-md text-xs font-medium ${colorClass}`}>
      {status}
    </span>
  );
};

