const RiskHeatmap = () => (
  <div className="grid grid-cols-3 gap-1 h-64 mt-4">
    {['Low', 'Medium', 'High'].map((impact, i) => (
      <div key={impact} className="flex flex-col gap-1">
        {[3, 2, 1].map((prob, j) => {
           const intensity = (i + 1) * prob;
           let bg = 'bg-green-900/40';
           if(intensity > 3) bg = 'bg-yellow-900/40';
           if(intensity > 6) bg = 'bg-red-900/40';
           return (
             <div key={j} className={`flex-1 rounded-md ${bg} flex items-center justify-center border border-white/5 hover:border-white/20 transition-all group`}>
                <span className="text-xs text-gray-500 group-hover:text-white transition-colors">{impact} / L{prob}</span>
             </div>
           )
        })}
      </div>
    ))}
  </div>
);

