import React, { useState, useEffect } from 'react';
import { GlassCard, PrimaryButton, Input, ProgressBar } from '../components/UIComponents';
import { UserRole } from '../types';
import { User, Shield, CheckCircle2, Cpu, ArrowRight } from 'lucide-react';

interface OnboardingProps {
  onComplete: (role: UserRole, name: string) => void;
}

const STEPS = ['Identity Verification', 'Clearance Assignment', 'System Sync'];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(0);
  const [name, setName] = useState('');
  const [selectedRole, setSelectedRole] = useState<UserRole>(UserRole.FIELD_WORKER);
  const [syncProgress, setSyncProgress] = useState(0);

  // Auto-progress logic for the final sync step
  useEffect(() => {
    if (step === 2) {
      const interval = setInterval(() => {
        setSyncProgress(prev => {
          if (prev >= 100) {
            clearInterval(interval);
            setTimeout(() => onComplete(selectedRole, name), 500);
            return 100;
          }
          // Random increments for "realistic" loading
          return prev + Math.random() * 15;
        });
      }, 400);
      return () => clearInterval(interval);
    }
  }, [step, onComplete, selectedRole, name]);

  const handleNext = () => {
    if (step === 0 && !name) return; // Validation
    setStep(prev => prev + 1);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#050505] p-4 relative">
       {/* Background Grid */}
       <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:40px_40px]" />

       <div className="w-full max-w-2xl relative z-10">

         {/* Progress Header */}
         <div className="flex justify-between items-end mb-8 px-2">
            <div>
              <h2 className="text-3xl font-display font-bold text-white mb-2">Unit Initialization</h2>
              <p className="text-gray-500">Step {step + 1} of {STEPS.length}: <span className="text-brand-yellow">{STEPS[step]}</span></p>
            </div>
            <div className="flex gap-2 mb-2">
              {STEPS.map((_, i) => (
                <div key={i} className={`h-1.5 w-8 rounded-full transition-colors ${i <= step ? 'bg-brand-yellow' : 'bg-gray-800'}`} />
              ))}
            </div>
         </div>

         <GlassCard className="min-h-[400px] flex flex-col justify-between">

           {/* STEP 1: IDENTITY */}
           {step === 0 && (
             <div className="animate-in fade-in slide-in-from-right-4 duration-500 space-y-6">
               <div className="text-center mb-8">
                 <div className="w-20 h-20 mx-auto bg-[#0a0a0a] rounded-full border border-dashed border-gray-700 flex items-center justify-center mb-4 group cursor-pointer hover:border-brand-yellow transition-colors">
                    <User className="text-gray-500 group-hover:text-brand-yellow transition-colors" size={32} />
                 </div>
                 <h3 className="text-xl font-medium text-white">Establish Profile</h3>
                 <p className="text-sm text-gray-500 max-w-xs mx-auto mt-2">Enter your designation name for the Global Fleet Registry.</p>
               </div>

               <div className="max-w-sm mx-auto space-y-4">
                  <Input 
                    label="Full Designation" 
                    placeholder="e.g. Alex Mercer" 
                    value={name} 
                    onChange={e => setName(e.target.value)} 
                    autoFocus
                  />
                  <div className="p-3 bg-brand-yellow/5 border border-brand-yellow/10 rounded-lg flex gap-3 items-start">
                    <Shield className="text-brand-yellow shrink-0 mt-0.5" size={16} />
                    <p className="text-xs text-brand-yellow/80">Your biometric data is encrypted securely in the NeuvArθeta Vault.</p>
                  </div>
               </div>
             </div>
           )}

           {/* STEP 2: ROLE SELECTION */}
           {step === 1 && (
             <div className="animate-in fade-in slide-in-from-right-4 duration-500 h-full flex flex-col">
               <h3 className="text-center text-xl font-medium text-white mb-6">Select Operational Clearance</h3>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-3 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                 {Object.values(UserRole).map((role) => (
                   <div 
                    key={role}
                    onClick={() => setSelectedRole(role)}
                    className={`
                      p-4 rounded-xl border cursor-pointer transition-all relative
                      ${selectedRole === role 
                        ? 'bg-brand-yellow/10 border-brand-yellow shadow-[0_0_15px_rgba(255,127,39,0.1)]' 
                        : 'bg-[#0a0a0a] border-white/5 hover:border-white/20 hover:bg-white/5'}
                    `}
                   >
                     <div className="flex justify-between items-center">
                       <span className={`font-display font-medium ${selectedRole === role ? 'text-brand-yellow' : 'text-gray-300'}`}>{role}</span>
                       {selectedRole === role && <CheckCircle2 size={18} className="text-brand-yellow" />}
                     </div>
                     <p className="text-xs text-gray-500 mt-1">Full access to {role.toLowerCase()} modules.</p>
                   </div>
                 ))}
               </div>
             </div>
           )}

           {/* STEP 3: SYNC */}
           {step === 2 && (
             <div className="animate-in fade-in zoom-in-95 duration-500 flex flex-col items-center justify-center h-full text-center py-10">
                <div className="relative mb-8">
                  <div className="absolute inset-0 bg-brand-yellow/20 rounded-full blur-xl animate-pulse" />
                  <Cpu size={64} className="text-brand-yellow relative z-10 animate-bounce" />
                </div>

                <h3 className="text-2xl font-display font-bold text-white mb-2">Synchronizing Neural Link</h3>
                <p className="text-gray-400 mb-8 max-w-sm">Provisioning dashboard widgets, decrypting fleet data, and establishing secure websocket connection...</p>

                <div className="w-full max-w-md">
                   <ProgressBar progress={syncProgress} label="System Initialization" />
                </div>

                <div className="mt-8 grid grid-cols-3 gap-4 text-xs text-gray-600 font-mono">
                   <div className="flex items-center gap-2">
