                    </div>
                    <p className={`text-sm ${msg.sender === 'You' ? 'text-black font-medium' : 'text-gray-300'}`}>{msg.content}</p>
                  </div>
                  <span className="text-[10px] text-gray-600 mt-1 px-1">{msg.timestamp}</span>
