                    className="flex-1 bg-black border border-white/10 rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:border-brand-yellow/50"
                 />
                 <button 
                  onClick={handleSendMessage}
                  className="bg-brand-yellow text-black p-2 rounded-xl hover:bg-brand-yellowDark transition-colors">
                   <Send size={20} />
                 </button>
               </div>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

