export const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  let colorClass = 'bg-gray-800 text-gray-300';
  if (status === 'Active' || status === 'Resolved' || status === 'Open') colorClass = 'bg-green-500/10 text-green-400 border border-green-500/20 shadow-[0_0_10px_rgba(74,222,128,0.1)]';
  if (status === 'Maintenance' || status === 'In Progress') colorClass = 'bg-brand-yellow/10 text-brand-yellow border border-brand-yellow/20 shadow-[0_0_10px_rgba(255,209,71,0.1)]';
  if (status === 'Critical' || status === 'Low Battery') colorClass = 'bg-red-500/10 text-red-400 border border-red-500/20 shadow-[0_0_10px_rgba(248,113,113,0.1)]';

  return (
    <span className={`px-2.5 py-1 rounded-md text-xs font-medium backdrop-blur-sm ${colorClass}`}>
      {status}
    </span>
  );
};

