export const ThemeAreaChart: React.FC<{ data: any[], dataKey: string, height?: number, color?: string }> = ({ data, dataKey, height = 300, color = '#FFD147' }) => (
  <ResponsiveContainer width="100%" height={height}>
    <AreaChart data={data}>
      <defs>
        {/* Glow Filter */}
        <filter id="glow" height="200%">
            <feGaussianBlur in="SourceAlpha" stdDeviation="3" result="blur" />
            <feOffset in="blur" dx="0" dy="0" result="offsetBlur" />
            <feFlood floodColor={color} floodOpacity="0.6" result="offsetColor" />
            <feComposite in="offsetColor" in2="offsetBlur" operator="in" result="offsetBlur" />
            <feMerge>
                <feMergeNode in="offsetBlur" />
                <feMergeNode in="SourceGraphic" />
            </feMerge>
        </filter>
        <linearGradient id={`color${dataKey}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="5%" stopColor={color} stopOpacity={0.4}/>
          <stop offset="95%" stopColor={color} stopOpacity={0}/>
        </linearGradient>
      </defs>
      <CartesianGrid strokeDasharray="3 3" stroke="#222" vertical={false} />
      <XAxis dataKey="name" stroke="#444" tick={{fill: '#666', fontSize: 11, fontFamily: 'Space Grotesk'}} tickLine={false} axisLine={false} dy={10} />
      <YAxis stroke="#444" tick={{fill: '#666', fontSize: 11, fontFamily: 'Space Grotesk'}} tickLine={false} axisLine={false} dx={-10} />
      <Tooltip 
        contentStyle={{ backgroundColor: 'rgba(10, 10, 10, 0.9)', backdropFilter: 'blur(20px)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '12px', boxShadow: '0 10px 40px rgba(0,0,0,0.5)' }}
        itemStyle={{ color: '#fff', fontSize: '12px', fontWeight: 500 }}
        cursor={{ stroke: color, strokeWidth: 1, strokeDasharray: '4 4' }}
      />
      <Area 
        type="monotone" 
        dataKey={dataKey} 
        stroke={color} 
        strokeWidth={2} 
        fillOpacity={1} 
        fill={`url(#color${dataKey})`} 
        filter="url(#glow)"
        animationDuration={1500}
      />
    </AreaChart>
  </ResponsiveContainer>
);

const COLORS = ['#FFD147', '#D4D4D4', '#666666', '#333333'];

export const ThemePieChart: React.FC<{ data: any[] }> = ({ data }) => (
  <ResponsiveContainer width="100%" height={300}>
