export const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  let colorClass = 'bg-gray-800 text-gray-300';
  if (status === 'Active' || status === 'Resolved' || status === 'Open') colorClass = 'bg-green-500/10 text-green-400 border border-green-500/20 shadow-[0_0_15px_rgba(74,222,128,0.15)]';
  if (status === 'Maintenance' || status === 'In Progress') colorClass = 'bg-brand-yellow/10 text-brand-yellow border border-brand-yellow/20 shadow-[0_0_15px_rgba(255,209,71,0.15)]';
  if (status === 'Critical' || status === 'Low Battery') colorClass = 'bg-red-500/10 text-red-400 border border-red-500/20 shadow-[0_0_15px_rgba(248,113,113,0.15)]';

  return (
    <span className={`px-3 py-1 rounded-full text-[10px] uppercase tracking-wider font-bold backdrop-blur-sm ${colorClass}`}>
      {status}
    </span>
  );
};

import React, { useState } from 'react';
import { UserRole, Message, User } from './types';
import { ROLE_NAV_ITEMS, ROLE_ICONS, MOCK_MESSAGES } from './constants';
import { RoleDashboard } from './views/RoleDashboards';
import { Auth } from './views/Auth';
import { Onboarding } from './views/Onboarding';
import { 
  Bell, 
  Search, 
  Menu, 
  X, 
  LogOut, 
  Settings, 
  ChevronRight, 
  MessageSquare, 
  Send 
} from 'lucide-react';

type ViewState = 'auth' | 'onboarding' | 'dashboard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('auth');
  const [user, setUser] = useState<User | null>(null);

  // Dashboard State
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.CEO);
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isChatOpen, setChatOpen] = useState(false);
  const [chatMessage, setChatMessage] = useState('');
  const [messages, setMessages] = useState<Message[]>(MOCK_MESSAGES);

  // Auth Handlers
  const handleLogin = (email: string) => {
    // Simulate fetching user data
    setUser({
      id: 'u-123',
      name: email.split('@')[0], // Extract name from email for demo
      role: UserRole.CEO,
      avatarUrl: `https://api.dicebear.com/7.x/shapes/svg?seed=${email}`
    });
    setCurrentRole(UserRole.CEO);
    setView('dashboard');
  };

  const handleOnboardingComplete = (role: UserRole, name: string) => {
    setUser({
      id: `u-${Date.now()}`,
      name: name,
      role: role,
      avatarUrl: `https://api.dicebear.com/7.x/shapes/svg?seed=${name}`
    });
    setCurrentRole(role);
    setView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setView('auth');
  };

  // Dashboard Handlers
  const handleRoleSwitch = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newRole = e.target.value as UserRole;
    setCurrentRole(newRole);
    // Update user object as well for consistency in UI
    if (user) setUser({ ...user, role: newRole });
    setSidebarOpen(false); 
  };

  const handleSendMessage = () => {
    if (!chatMessage.trim()) return;
    const newMsg: Message = {
      id: Date.now().toString(),
      sender: 'You',
      role: currentRole,
      content: chatMessage,
      timestamp: 'Just now',
      tags: []
    };
    setMessages([...messages, newMsg]);
    setChatMessage('');
  };

  // ----------------------------------------------------------------------
  // View Rendering Logic
  // ----------------------------------------------------------------------

  if (view === 'auth') {
    return <Auth onLogin={handleLogin} onStartOnboarding={() => setView('onboarding')} />;
  }

  if (view === 'onboarding') {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  // Dashboard View
  const RoleIcon = ROLE_ICONS[currentRole];

  return (
    <div className="flex h-screen text-gray-200 overflow-hidden font-sans selection:bg-brand-yellow/30 selection:text-white animate-in fade-in duration-1000">

      {/* ---------------- Sidebar ---------------- */}
      <aside 
        className={`
          fixed inset-y-0 left-0 z-50 w-64 
          bg-[#050505]/95 backdrop-blur-2xl border-r border-white/5
          transform transition-transform duration-300 ease-in-out
          shadow-[5px_0_30px_rgba(0,0,0,0.5)]
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
          md:relative md:translate-x-0
        `}
      >
        <div className="p-6 flex items-center gap-3 relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-r from-brand-yellow/5 to-transparent opacity-50"></div>
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-brand-yellow to-brand-yellowDark flex items-center justify-center shadow-[0_0_15px_rgba(255,209,71,0.3)] relative z-10">
            <span className="font-display font-bold text-black text-lg">N</span>
          </div>
          <span className="font-display font-bold text-xl tracking-wide text-white relative z-10">BUZANGER</span>
        </div>

        <div className="px-6 mb-8">
           <div className="text-[10px] font-bold text-gray-600 uppercase tracking-widest mb-2">Simulate Role</div>
           <div className="relative group">
             <select 
               value={currentRole} 
               onChange={handleRoleSwitch}
               className="w-full bg-[#111] border border-white/10 rounded-lg py-2.5 px-3 text-sm text-gray-300 focus:outline-none focus:border-brand-yellow/50 focus:bg-[#161616] appearance-none cursor-pointer transition-all"
             >
               {Object.values(UserRole).map(role => (
                 <option key={role} value={role}>{role}</option>
               ))}
             </select>
             <div className="absolute right-3 top-3 pointer-events-none text-gray-500 group-hover:text-brand-yellow transition-colors">
               <ChevronRight size={14} className="rotate-90" />
             </div>
           </div>
        </div>

        <nav className="px-4 space-y-1">
          <div className="px-4 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-widest">
            Module Access
          </div>
          {ROLE_NAV_ITEMS[currentRole].map((item, idx) => (
            <button key={item} className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all duration-200 group ${idx === 0 ? 'bg-gradient-to-r from-brand-yellow to-brand-yellowDark text-black shadow-[0_0_20px_rgba(255,209,71,0.3)]' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}>
              <div className={idx === 0 ? '' : 'group-hover:text-brand-yellow transition-colors opacity-70'}>
                 <RoleIcon size={18} /> 
              </div>
              {item}
            </button>
          ))}

           <div className="px-4 py-2 mt-8 text-[10px] font-bold text-gray-600 uppercase tracking-widest">
            System
          </div>
          <button className="w-full flex items-center gap-3 px-4 py-3 text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 rounded-xl transition-colors group">
            <Settings size={18} className="group-hover:rotate-90 transition-transform duration-500" /> Settings
          </button>
          <button onClick={() => setChatOpen(true)} className="w-full flex items-center gap-3 px-4 py-3 text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 rounded-xl transition-colors group">
            <MessageSquare size={18} className="group-hover:scale-110 transition-transform" /> Communication Hub
          </button>
        </nav>

        <div className="absolute bottom-0 left-0 right-0 p-6 border-t border-white/5 bg-gradient-to-t from-black to-transparent backdrop-blur-md">
          <div className="flex items-center gap-3">
            {user && (
               <img src={user.avatarUrl} alt="User" className="w-10 h-10 rounded-full border border-white/10 bg-white/5 shadow-inner" />
            )}
            <div className="flex-1 min-w-0">
              <p className="text-sm font-semibold text-white truncate capitalize tracking-wide">{user?.name || 'Unknown Unit'}</p>
              <p className="text-[10px] text-brand-yellow truncate uppercase tracking-wider">{currentRole}</p>
            </div>
            <button
              onClick={handleLogout}
              title="Logout"
              className="text-gray-500 hover:text-red-400 cursor-pointer transition-colors p-2 hover:bg-white/5 rounded-lg"
            >
              <LogOut size={16} />
            </button>
          </div>
        </div>
      </aside>

      {/* ---------------- Main Content ---------------- */}
      <main className="flex-1 flex flex-col min-w-0 relative">
        {/* Top Header */}
        <header className="h-20 flex items-center justify-between px-8 sticky top-0 z-40 transition-all duration-300">
           {/* Glass Background for Header */}
           <div className="absolute inset-0 bg-[#050505]/60 backdrop-blur-md border-b border-white/5"></div>

          <div className="flex items-center gap-4 relative z-10">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="md:hidden text-gray-400 hover:text-white">
              <Menu size={24} />
            </button>
            <div className="flex flex-col">
              <span className="text-[10px] text-gray-500 font-mono uppercase tracking-widest">Workspace</span>
              <h1 className="text-xl font-display font-bold text-white flex items-center gap-2">
                 {currentRole} Dashboard
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-6 relative z-10">
            <div className="relative hidden sm:block group">
              <Search className="absolute left-3 top-2.5 text-gray-600 group-focus-within:text-brand-yellow transition-colors" size={16} />
              <input 
                type="text" 
                placeholder="Search fleet, tickets..." 
                className="bg-[#111] border border-white/10 rounded-full pl-10 pr-4 py-2 text-sm text-gray-300 focus:outline-none focus:border-brand-yellow/50 focus:w-72 transition-all w-56 placeholder-gray-700 shadow-inner"
              />
            </div>
            <button className="relative text-gray-400 hover:text-white transition-colors p-2 hover:bg-white/5 rounded-full">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-brand-yellow rounded-full shadow-[0_0_10px_rgba(255,209,71,0.8)] animate-pulse"></span>
            </button>
          </div>
        </header>

        {/* Scrollable Dashboard View */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8 relative z-0 custom-scrollbar">
          <RoleDashboard role={currentRole} />
        </div>

      </main>

      {/* ---------------- Chat Overlay (Communication Hub) ---------------- */}
      {isChatOpen && (
        <div className="fixed inset-0 z-50 flex justify-end bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="w-full max-w-md bg-[#0a0a0a] h-full shadow-2xl border-l border-white/10 flex flex-col animate-in slide-in-from-right duration-300">
            <div className="h-16 border-b border-white/5 flex items-center justify-between px-6 bg-[#0f0f0f]">
               <h3 className="font-display font-bold text-lg text-white flex items-center gap-2">
                 <span className="w-2 h-2 rounded-full bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)]"></span>
                 Communication Hub
               </h3>
               <button onClick={() => setChatOpen(false)} className="text-gray-400 hover:text-white hover:bg-white/5 p-2 rounded-lg transition-colors">
                 <X size={20} />
               </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-opacity-5">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex flex-col ${msg.sender === 'You' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 shadow-lg ${msg.sender === 'You' ? 'bg-gradient-to-br from-brand-yellow to-brand-yellowDark text-black' : 'bg-[#1a1a1a] border border-white/10 backdrop-blur-md'}`}>
                    <div className="flex items-center gap-2 mb-1.5">
                      <span className={`text-[10px] font-bold uppercase tracking-wider ${msg.sender === 'You' ? 'text-black/70' : 'text-brand-yellow'}`}>{msg.sender}</span>
                      <span className={`text-[9px] ${msg.sender === 'You' ? 'text-black/50' : 'text-gray-500'}`}>{msg.role}</span>
                    </div>
                    <p className={`text-sm leading-relaxed ${msg.sender === 'You' ? 'text-black font-medium' : 'text-gray-200'}`}>{msg.content}</p>
                  </div>
                  <span className="text-[10px] text-gray-600 mt-1.5 px-1 font-mono">{msg.timestamp}</span>
                </div>
              ))}
            </div>

            <div className="p-4 border-t border-white/5 bg-[#0f0f0f]">
               <div className="flex gap-2">
                 <input 
                    type="text" 
                    value={chatMessage}
                    onChange={(e) => setChatMessage(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                    placeholder="Type message or tag @team..."
                    className="flex-1 bg-[#050505] border border-white/10 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-brand-yellow/50 focus:ring-1 focus:ring-brand-yellow/20 transition-all placeholder-gray-700"
                 />
                 <button 
                  onClick={handleSendMessage}
                  className="bg-brand-yellow text-black p-3 rounded-xl hover:bg-brand-yellowDark transition-all shadow-[0_0_15px_rgba(255,209,71,0.2)] hover:scale-105 active:scale-95">
                   <Send size={20} />
                 </button>
               </div>
            </div>
          </div>
        </div>
      )}

    </div>
  );
};

export default App;

