      <XAxis dataKey="name" stroke="#555" tick={{fill: '#666', fontSize: 11, fontWeight: 500}} tickLine={false} axisLine={false} dy={10} />
      <YAxis stroke="#555" tick={{fill: '#666', fontSize: 11, fontWeight: 500}} tickLine={false} axisLine={false} />
      <Tooltip 
        contentStyle={{ backgroundColor: 'rgba(28, 28, 30, 0.9)', backdropFilter: 'blur(12px)', border: 'none', borderRadius: '12px', boxShadow: '0 10px 30px rgba(0,0,0,0.5)', padding: '12px' }}
        itemStyle={{ color: '#fff', fontSize: '13px', fontWeight: 600 }}
        cursor={{ stroke: '#555', strokeWidth: 1 }}
      />
      <Area 
        type="monotone" 
        dataKey={dataKey} 
        stroke={color} 
