export const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  let colorClass = 'bg-gray-800/50 text-gray-300';
  if (status === 'Active' || status === 'Resolved' || status === 'Open') colorClass = 'bg-green-500/10 text-green-400';
  if (status === 'Maintenance' || status === 'In Progress') colorClass = 'bg-brand-yellow/10 text-brand-yellow';
  if (status === 'Critical' || status === 'Low Battery') colorClass = 'bg-red-500/10 text-red-400';

  return (
    <span className={`px-3 py-1 rounded-full text-xs font-medium backdrop-blur-md ${colorClass} border border-white/5`}>
      {status}
    </span>
  );
};

import React, { useState } from 'react';
