              </div>
              <input 
                type="text" 
                placeholder="Search..." 
                className="bg-[#1C1C1E] border border-transparent rounded-xl pl-10 pr-12 py-2 text-sm text-white focus:outline-none focus:bg-[#2C2C2E] focus:ring-2 focus:ring-brand-yellow/20 transition-all w-64 placeholder-gray-500 font-medium"
