import React, { useState, useEffect } from 'react';
import { GlassCard, PrimaryButton, Input, ProgressBar } from '../components/UIComponents';
import { UserRole } from '../types';
import { User, Shield, CheckCircle2, Cpu, ArrowRight, Activity } from 'lucide-react';

interface OnboardingProps {
  onComplete: (role: UserRole, name: string) => void;
}

const STEPS = ['Identity', 'Clearance', 'Sync'];

export const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(0);
  const [name, setName] = useState('');
  const [selectedRole, setSelectedRole] = useState<UserRole>(UserRole.FIELD_WORKER);
  const [syncProgress, setSyncProgress] = useState(0);

  useEffect(() => {
    if (step === 2) {
      const interval = setInterval(() => {
        setSyncProgress(prev => {
          if (prev >= 100) {
            clearInterval(interval);
            setTimeout(() => onComplete(selectedRole, name), 800);
            return 100;
          }
          return prev + Math.random() * 8;
        });
      }, 300);
      return () => clearInterval(interval);
    }
  }, [step, onComplete, selectedRole, name]);

  const handleNext = () => {
    if (step === 0 && !name) return;
    setStep(prev => prev + 1);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-6 relative">

       <div className="w-full max-w-2xl relative z-10">
         <div className="flex justify-between items-end mb-10 px-2">
            <div>
              <h2 className="text-3xl font-display font-bold text-white mb-2 tracking-tight">System Initialization</h2>
              <div className="flex gap-3 text-sm font-medium text-gray-500">
                {STEPS.map((s, i) => (
                    <span key={i} className={i === step ? 'text-white' : ''}>{i + 1}. {s}</span>
                ))}
              </div>
            </div>
         </div>

         <GlassCard className="min-h-[450px] flex flex-col justify-between p-8">

           {/* STEP 1: IDENTITY */}
           {step === 0 && (
             <div className="animate-in fade-in slide-in-from-right-8 duration-500 space-y-8 flex flex-col items-center justify-center h-full">
               <div className="w-24 h-24 bg-[#2C2C2E] rounded-full flex items-center justify-center mb-2">
                 <User className="text-white" size={32} />
               </div>

               <div className="w-full max-w-sm space-y-6">
                  <div className="text-center">
                    <h3 className="text-xl font-bold text-white mb-2">Establish Profile</h3>
                    <p className="text-sm text-gray-400">Enter your designation name for the registry.</p>
                  </div>
                  <Input 
                    label="Full Designation" 
                    placeholder="e.g. Alex Mercer" 
                    value={name} 
                    onChange={e => setName(e.target.value)} 
                    autoFocus
                    className="text-center text-lg"
                  />
               </div>
             </div>
           )}

           {/* STEP 2: ROLE SELECTION */}
           {step === 1 && (
             <div className="animate-in fade-in slide-in-from-right-8 duration-500 h-full flex flex-col">
               <h3 className="text-xl font-bold text-white mb-6">Select Operational Clearance</h3>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-4 max-h-[320px] overflow-y-auto pr-2 custom-scrollbar">
                 {Object.values(UserRole).map((role) => (
                   <div 
                    key={role}
                    onClick={() => setSelectedRole(role)}
                    className={`
                      p-4 rounded-2xl border cursor-pointer transition-all relative flex items-center justify-between
                      ${selectedRole === role 
                        ? 'bg-white text-black border-transparent shadow-lg' 
                        : 'bg-[#2C2C2E] border-transparent text-gray-400 hover:bg-[#3A3A3C] hover:text-white'}
                    `}
                   >
                     <span className="font-medium">{role}</span>
                     {selectedRole === role && <CheckCircle2 size={18} className="text-black" />}
                   </div>
                 ))}
               </div>
             </div>
           )}

           {/* STEP 3: SYNC */}
           {step === 2 && (
             <div className="animate-in fade-in zoom-in-95 duration-700 flex flex-col items-center justify-center h-full text-center py-10">
                <div className="relative mb-10">
                  <div className="w-20 h-20 bg-brand-yellow rounded-full flex items-center justify-center animate-pulse">
                     <Activity size={32} className="text-black" />
                  </div>
                </div>

                <h3 className="text-2xl font-bold text-white mb-3">Synchronizing</h3>
                <p className="text-gray-400 mb-10 max-w-sm text-sm font-medium">Decrypting fleet data and establishing secure link...</p>

                <div className="w-full max-w-md">
                   <ProgressBar progress={syncProgress} />
                </div>
             </div>
           )}

           {/* Navigation Buttons */}
           {step < 2 && (
             <div className="mt-8 pt-8 border-t border-white/5 flex justify-end">
                <PrimaryButton onClick={handleNext} className="bg-white text-black px-8">
                   {step === 1 ? 'Initialize' : 'Continue'} <ArrowRight size={18} />
                </PrimaryButton>
             </div>
           )}

         </GlassCard>
       </div>
    </div>
  );
};

