import React, { useState } from 'react';
import { UserRole, Message, User } from './types';
import { ROLE_NAV_ITEMS, ROLE_ICONS, MOCK_MESSAGES } from './constants';
import { RoleDashboard } from './views/RoleDashboards';
import { Auth } from './views/Auth';
import { Onboarding } from './views/Onboarding';
import { 
  Bell, 
  Search, 
  Menu, 
  X, 
  LogOut, 
  Settings, 
  ChevronRight, 
  MessageSquare, 
  Send,
  Command
} from 'lucide-react';

type ViewState = 'auth' | 'onboarding' | 'dashboard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('auth');
  const [user, setUser] = useState<User | null>(null);

  // Dashboard State
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.CEO);
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isChatOpen, setChatOpen] = useState(false);
  const [chatMessage, setChatMessage] = useState('');
  const [messages, setMessages] = useState<Message[]>(MOCK_MESSAGES);

  // Auth Handlers
  const handleLogin = (email: string) => {
    // Simulate fetching user data
    setUser({
      id: 'u-123',
      name: email.split('@')[0], 
      role: UserRole.CEO,
      avatarUrl: `https://api.dicebear.com/7.x/notionists/svg?seed=${email}`
    });
    setCurrentRole(UserRole.CEO);
    setView('dashboard');
  };

  const handleOnboardingComplete = (role: UserRole, name: string) => {
    setUser({
      id: `u-${Date.now()}`,
      name: name,
      role: role,
      avatarUrl: `https://api.dicebear.com/7.x/notionists/svg?seed=${name}`
    });
    setCurrentRole(role);
    setView('dashboard');
  };

  const handleLogout = () => {
    setUser(null);
    setView('auth');
  };

  // Dashboard Handlers
  const handleRoleSwitch = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newRole = e.target.value as UserRole;
    setCurrentRole(newRole);
    if (user) setUser({ ...user, role: newRole });
    setSidebarOpen(false); 
  };

  const handleSendMessage = () => {
    if (!chatMessage.trim()) return;
    const newMsg: Message = {
      id: Date.now().toString(),
      sender: 'You',
      role: currentRole,
      content: chatMessage,
      timestamp: 'Just now',
      tags: []
    };
    setMessages([...messages, newMsg]);
    setChatMessage('');
  };

  // ----------------------------------------------------------------------
  // View Rendering Logic
  // ----------------------------------------------------------------------

  if (view === 'auth') {
    return <Auth onLogin={handleLogin} onStartOnboarding={() => setView('onboarding')} />;
  }

  if (view === 'onboarding') {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  // Dashboard View
  const RoleIcon = ROLE_ICONS[currentRole];

  return (
    <div className="flex h-screen text-gray-200 overflow-hidden font-sans selection:bg-brand-yellow selection:text-black">

      {/* ---------------- Sidebar ---------------- */}
      <aside 
        className={`
          fixed inset-y-0 left-0 z-50 w-72 
          bg-[#0A0A0A]/90 backdrop-blur-2xl border-r border-white/[0.05]
          transform transition-transform duration-500 cubic-bezier(0.32, 0.72, 0, 1)
          shadow-2xl
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
          md:relative md:translate-x-0
          flex flex-col
        `}
      >
        <div className="p-8 pb-6">
           <div className="flex items-center gap-3 mb-8">
             <div className="w-10 h-10 rounded-xl bg-brand-yellow flex items-center justify-center shadow-[0_0_15px_rgba(254,218,10,0.4)]">
               <span className="font-display font-bold text-black text-xl">N</span>
             </div>
             <div>
               <h1 className="font-display font-bold text-lg text-white leading-none tracking-tight">BUZANGER</h1>
               <span className="text-[10px] font-bold text-brand-yellow uppercase tracking-widest">Enterprise v4.0</span>
             </div>
           </div>

           <div className="mb-2">
             <label className="text-[10px] font-bold text-gray-600 uppercase tracking-widest mb-3 block pl-2">Simulation Context</label>
             <div className="relative group">
               <select 
                 value={currentRole} 
                 onChange={handleRoleSwitch}
                 className="w-full bg-[#181818] border border-white/5 rounded-xl py-3 pl-4 pr-10 text-sm text-gray-300 font-medium focus:outline-none focus:border-brand-yellow/30 focus:text-brand-yellow appearance-none cursor-pointer transition-all hover:bg-[#222]"
               >
                 {Object.values(UserRole).map(role => (
                   <option key={role} value={role}>{role}</option>
                 ))}
               </select>
               <div className="absolute right-4 top-3.5 pointer-events-none text-gray-600 group-hover:text-brand-yellow transition-colors">
                 <ChevronRight size={16} className="rotate-90" />
               </div>
             </div>
           </div>
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto custom-scrollbar">
          <div className="px-4 py-3 text-[10px] font-bold text-gray-600 uppercase tracking-widest">
            Module Access
          </div>
          {ROLE_NAV_ITEMS[currentRole].map((item, idx) => (
            <button key={item} className={`w-full flex items-center gap-3.5 px-4 py-3.5 text-sm font-bold rounded-xl transition-all duration-200 group ${idx === 0 ? 'bg-brand-yellow text-black shadow-[0_0_20px_rgba(254,218,10,0.2)]' : 'text-gray-400 hover:text-white hover:bg-[#1A1A1A]'}`}>
              <div className={idx === 0 ? 'text-black' : 'text-gray-600 group-hover:text-brand-yellow transition-colors'}>
                 <RoleIcon size={18} strokeWidth={2.5} /> 
              </div>
              {item}
            </button>
          ))}

           <div className="px-4 py-3 mt-6 text-[10px] font-bold text-gray-600 uppercase tracking-widest">
            System
          </div>
          <button className="w-full flex items-center gap-3.5 px-4 py-3.5 text-sm font-medium text-gray-400 hover:text-white hover:bg-[#1A1A1A] rounded-xl transition-colors group">
            <Settings size={18} strokeWidth={2} className="group-hover:text-brand-yellow transition-colors" /> Settings
          </button>
          <button onClick={() => setChatOpen(true)} className="w-full flex items-center gap-3.5 px-4 py-3.5 text-sm font-medium text-gray-400 hover:text-white hover:bg-[#1A1A1A] rounded-xl transition-colors group">
            <MessageSquare size={18} strokeWidth={2} className="group-hover:text-brand-yellow transition-colors" /> Communication Hub
          </button>
        </nav>

        <div className="p-4 m-4 bg-[#111] rounded-2xl border border-white/5 shadow-inner">
          <div className="flex items-center gap-3">
            {user && (
               <img src={user.avatarUrl} alt="User" className="w-10 h-10 rounded-full bg-gray-800 border border-white/10" />
            )}
            <div className="flex-1 min-w-0">
              <p className="text-sm font-bold text-white truncate capitalize">{user?.name || 'Unknown'}</p>
              <p className="text-[10px] text-brand-yellow truncate uppercase font-bold tracking-wider">{currentRole}</p>
            </div>
            <button
              onClick={handleLogout}
              title="Logout"
              className="text-gray-600 hover:text-red-400 transition-colors p-2"
            >
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </aside>

      {/* ---------------- Main Content ---------------- */}
      <main className="flex-1 flex flex-col min-w-0 relative">
        {/* Top Header */}
        <header className="h-24 flex items-center justify-between px-8 sticky top-0 z-40 transition-all duration-300 pointer-events-none">
           <div className="absolute inset-0 bg-gradient-to-b from-[#000000] to-transparent pointer-events-none"></div>

          <div className="flex items-center gap-4 relative z-10 pointer-events-auto">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="md:hidden text-gray-400 hover:text-brand-yellow">
              <Menu size={24} />
            </button>
            <div className="flex flex-col">
              <h1 className="text-2xl font-display font-bold text-white flex items-center gap-2 tracking-tight">
                 <span className="text-brand-yellow">//</span> {currentRole} Dashboard
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-5 relative z-10 pointer-events-auto">
            <div className="relative hidden sm:block group">
              <Search className="absolute left-3 top-2.5 text-gray-600 group-focus-within:text-brand-yellow transition-colors" size={16} />
              <div className="absolute right-3 top-2.5 flex items-center gap-1 pointer-events-none">
                 <Command size={10} className="text-gray-700" />
                 <span className="text-[10px] text-gray-700 font-bold">K</span>
              </div>
              <input 
                type="text" 
                placeholder="Query system..." 
                className="bg-[#121212] border border-white/5 rounded-xl pl-10 pr-12 py-2 text-sm text-white focus:outline-none focus:bg-[#000] focus:border-brand-yellow/50 transition-all w-64 placeholder-gray-600 font-medium shadow-lg"
              />
