            <button className="relative text-gray-400 hover:text-brand-yellow transition-colors p-2 rounded-full hover:bg-white/5">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-brand-yellow rounded-full shadow-[0_0_8px_#FEDA0A]"></span>
            </button>
          </div>
        </header>

        {/* Scrollable Dashboard View */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 pt-4 relative z-0 custom-scrollbar">
          <div className="max-w-7xl mx-auto">
             <RoleDashboard role={currentRole} />
