      </main>

      {/* ---------------- Chat Overlay (Communication Hub) ---------------- */}
      {isChatOpen && (
        <div className="fixed inset-0 z-50 flex justify-end bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="w-full max-w-md bg-[#0C0C0C] h-full shadow-2xl border-l border-white/10 flex flex-col animate-in slide-in-from-right duration-500 ease-out">
            <div className="h-20 border-b border-white/5 flex items-center justify-between px-8 bg-[#111]">
               <h3 className="font-display font-bold text-xl text-white">Communication Hub</h3>
               <button onClick={() => setChatOpen(false)} className="text-gray-500 hover:text-white p-2 rounded-full hover:bg-white/10 transition-colors">
                 <X size={20} />
               </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-opacity-5">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex flex-col ${msg.sender === 'You' ? 'items-end' : 'items-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm border ${msg.sender === 'You' ? 'bg-brand-yellow text-black border-brand-yellow shadow-[0_0_15px_rgba(254,218,10,0.2)]' : 'bg-[#1A1A1A] text-gray-200 border-white/5'}`}>
                    <div className="flex items-center gap-2 mb-1">
                      <span className={`text-[10px] font-bold uppercase tracking-wider ${msg.sender === 'You' ? 'text-black/60' : 'text-brand-yellow'}`}>{msg.sender}</span>
                    </div>
                    <p className="text-sm font-medium leading-relaxed">{msg.content}</p>
                  </div>
                  <span className="text-[10px] text-gray-600 mt-2 font-mono">{msg.timestamp}</span>
                </div>
              ))}
            </div>

            <div className="p-6 border-t border-white/5 bg-[#111]">
               <div className="flex gap-3">
                 <input 
                    type="text" 
                    value={chatMessage}
                    onChange={(e) => setChatMessage(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                    placeholder="Type message..."
                    className="flex-1 bg-[#050505] border border-white/10 rounded-xl px-6 py-3.5 text-sm text-white focus:outline-none focus:border-brand-yellow/50 transition-all font-medium placeholder-gray-700"
