          <button onClick={() => setChatOpen(true)} className="w-full flex items-center gap-3.5 px-4 py-3.5 text-sm font-medium text-gray-400 hover:text-white hover:bg-[#1A1A1A] rounded-xl transition-colors group">
            <MessageSquare size={18} strokeWidth={2} className="group-hover:text-brand-yellow transition-colors" /> Communication Hub
          </button>
        </nav>

        <div className="p-4 m-4 bg-[#111] rounded-2xl border border-white/5 shadow-inner">
          <div className="flex items-center gap-3">
            {user && (
