        </div>
      </aside>

      {/* ---------------- Main Content ---------------- */}
      <main className="flex-1 flex flex-col min-w-0 relative">
        {/* Top Header */}
        <header className="h-24 flex items-center justify-between px-8 sticky top-0 z-40 transition-all duration-300 pointer-events-none">
           <div className="absolute inset-0 bg-gradient-to-b from-[#000000] to-transparent pointer-events-none"></div>

          <div className="flex items-center gap-4 relative z-10 pointer-events-auto">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="md:hidden text-gray-400 hover:text-brand-yellow">
              <Menu size={24} />
            </button>
            <div className="flex flex-col">
              <h1 className="text-2xl font-display font-bold text-white flex items-center gap-2 tracking-tight">
                 <span className="text-brand-yellow">//</span> {activeTab}
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-5 relative z-10 pointer-events-auto">
            <div className="relative hidden sm:block group">
              <Search className="absolute left-3 top-2.5 text-gray-600 group-focus-within:text-brand-yellow transition-colors" size={16} />
              <div className="absolute right-3 top-2.5 flex items-center gap-1 pointer-events-none">
                 <Command size={10} className="text-gray-700" />
                 <span className="text-[10px] text-gray-700 font-bold">K</span>
