          <GlassCard className="h-32 flex flex-col justify-center">
             <div className="flex items-center gap-4">
                <div className="bg-brand-yellow/10 p-3 rounded-xl text-brand-yellow">
                   <AlertTriangle size={24} />
                </div>
                <div>
                   <div className="text-xl font-display font-bold text-white">
                     {vehicles.filter(v => v.status !== 'Active').length} Units
                   </div>
                   <div className="text-xs text-gray-500 uppercase font-bold">Require Attention</div>
                </div>
             </div>
          </GlassCard>
       </div>
    </div>
  );
};

