interface ExtendedFleetVehicle extends FleetVehicle {
  history: [number, number][]; // [top, left] tuples
}

const LiveFleetMap = () => {
  // Initialize fleet state with random positions based on ID
  const [vehicles, setVehicles] = useState<ExtendedFleetVehicle[]>(() => {
    return MOCK_FLEET.map(v => {
       const num = parseInt(v.id.split('-')[1]);
       const top = (num * 37) % 80 + 10;
       const left = (num * 53) % 80 + 10;
       return { ...v, location: [top, left] as [number, number], history: [] };
    });
  });

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<'All' | 'Active' | 'Maintenance' | 'Low Battery'>('All');

  // Viewport State
  const [view, setView] = useState({ x: 0, y: 0, scale: 1 });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });

  // Simulation Engine
  useEffect(() => {
    const timer = setInterval(() => {
        setVehicles(prevVehicles => prevVehicles.map(vehicle => {
            // Don't update vehicles in maintenance
            if (vehicle.status === 'Maintenance') return vehicle;

            let [top, left] = vehicle.location;
            let currentBattery = vehicle.battery;
            let currentStatus = vehicle.status;

            // 1. Simulate Movement (Random Walk with center bias)
            // Bias helps keep them on the screen mostly
            const centerBiasX = (50 - left) * 0.005;
            const centerBiasY = (50 - top) * 0.005;

            // Random delta
            const deltaX = (Math.random() - 0.5) * 4 + centerBiasX;
            const deltaY = (Math.random() - 0.5) * 4 + centerBiasY;

            let newTop = top + deltaY;
            let newLeft = left + deltaX;

            // Soft boundaries
            newTop = Math.max(5, Math.min(95, newTop));
            newLeft = Math.max(5, Math.min(95, newLeft));

            // 2. Simulate Battery Drain
            if (Math.random() > 0.9 && currentBattery > 0) {
               currentBattery -= 1;
            }

            // 3. Status Logic
            if (currentBattery < 20) {
               currentStatus = 'Low Battery';
            } else if (currentBattery >= 20 && currentStatus === 'Low Battery') {
               currentStatus = 'Active'; 
            }

            // Store history: [top, left]
            // Keep last 20 points
            const point: [number, number] = [top, left];
            const newHistory = [...vehicle.history, point].slice(-20) as [number, number][];

            return {
                ...vehicle,
                location: [newTop, newLeft] as [number, number],
                history: newHistory,
                battery: currentBattery,
                status: currentStatus,
                lastPing: 'Just now'
            };
        }));
    }, 2000);

    return () => clearInterval(timer);
  }, []);

  const selectedVehicle = vehicles.find(v => v.id === selectedId) || null;
  const filteredVehicles = vehicles.filter(v => filterStatus === 'All' || v.status === filterStatus);

  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault(); // Prevent text selection
    setIsDragging(true);
    setDragStart({ x: e.clientX - view.x, y: e.clientY - view.y });
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    setView(prev => ({
      ...prev,
      x: e.clientX - dragStart.x,
      y: e.clientY - dragStart.y
    }));
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleZoom = (delta: number) => {
    setView(prev => ({
      ...prev,
      scale: Math.min(Math.max(prev.scale + delta, 0.5), 3)
    }));
  };

  const handleReset = () => {
    setView({ x: 0, y: 0, scale: 1 });
  };

  return (
    <div className="flex flex-col lg:flex-row h-[700px] gap-6 animate-in fade-in zoom-in-95 duration-500">
       {/* Main Map Area */}
       <div 
         className={`flex-1 relative rounded-3xl overflow-hidden bg-[#0a0a0a] border border-white/10 shadow-2xl group ${isDragging ? 'cursor-grabbing' : 'cursor-grab'}`}
         onMouseDown={handleMouseDown}
         onMouseMove={handleMouseMove}
         onMouseUp={handleMouseUp}
         onMouseLeave={handleMouseUp}
       >

           {/* Transformable Container */}
           <div 
             className="w-full h-full absolute inset-0 transition-transform duration-75 ease-linear origin-center"
             style={{ 
               transform: `translate(${view.x}px, ${view.y}px) scale(${view.scale})`,
               transition: isDragging ? 'none' : 'transform 2s linear' // Smoother transition for auto updates, instant for drag
             }}
           >
               {/* Map Background Layers */}
               <div className="absolute inset-[-50%] w-[200%] h-[200%] opacity-30 pointer-events-none">
                  <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
                     <defs>
                        <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
                          <path d="M 40 0 L 0 0 0 40" fill="none" stroke="#333" strokeWidth="1"/>
                        </pattern>
                        <pattern id="city-blocks" width="200" height="200" patternUnits="userSpaceOnUse">
                            <rect x="10" y="10" width="80" height="80" fill="#151515" />
                            <rect x="110" y="10" width="80" height="180" fill="#151515" />
                            <rect x="10" y="110" width="80" height="80" fill="#151515" />
                        </pattern>
                     </defs>
                     <rect width="100%" height="100%" fill="url(#grid)" />
                     <rect width="100%" height="100%" fill="url(#city-blocks)" opacity="0.6" />
                  </svg>
               </div>

               {/* Path History Layer */}
               <svg className="absolute inset-0 w-full h-full pointer-events-none z-0" viewBox="0 0 100 100" preserveAspectRatio="none">
                  {filteredVehicles.map(v => {
                     // Only show path for selected vehicle
                     if (v.id !== selectedId || v.history.length === 0) return null;

                     // "left" is x, "top" is y
                     const points = [
                        ...v.history.map(h => `${h[1]},${h[0]}`),
                        `${v.location[1]},${v.location[0]}`
                     ].join(' ');

                     return (
                        <g key={`path-${v.id}`}>
                           <polyline 
                              points={points}
                              fill="none"
                              stroke="#FEDA0A"
                              strokeWidth="0.3"
                              strokeOpacity="0.6"
                              strokeLinecap="round"
                              strokeLinejoin="round"
                              className="drop-shadow-[0_0_4px_#FEDA0A]"
                           />
                           {/* Start Point Dot */}
                           <circle cx={v.history[0][1]} cy={v.history[0][0]} r="0.4" fill="#FEDA0A" opacity="0.4" />
                        </g>
                     )
                  })}
               </svg>

               {/* Vehicle Markers */}
               {filteredVehicles.map(vehicle => {
                 const isSelected = selectedId === vehicle.id;
                 let statusColor = 'bg-brand-yellow';
                 let statusGlow = 'shadow-[0_0_15px_#FEDA0A]';
                 let hoverGlow = 'group-hover/marker:shadow-[0_0_25px_#FEDA0A]';

                 if (vehicle.status === 'Maintenance') { 
                    statusColor = 'bg-orange-500'; 
                    statusGlow = 'shadow-[0_0_15px_#f97316]'; 
                    hoverGlow = 'group-hover/marker:shadow-[0_0_25px_#f97316]';
                 }
                 if (vehicle.status === 'Low Battery') { 
                    statusColor = 'bg-red-500'; 
                    statusGlow = 'shadow-[0_0_15px_#ef4444]'; 
                    hoverGlow = 'group-hover/marker:shadow-[0_0_25px_#ef4444]';
                 }

                 return (
                   <div 
                     key={vehicle.id}
                     onClick={(e) => { e.stopPropagation(); setSelectedId(vehicle.id); }}
                     className="absolute cursor-pointer group/marker z-10"
                     style={{ 
                         top: `${vehicle.location[0]}%`, 
                         left: `${vehicle.location[1]}%`,
                         transition: 'top 2s linear, left 2s linear' // Smooth movement between updates
                     }}
                   >
                      <div className={`
                         w-4 h-4 rounded-full border-2 border-[#121212] ${statusColor} ${statusGlow} ${hoverGlow}
                         transition-all duration-300
                         ${isSelected ? 'scale-150 ring-4 ring-white/20 z-20' : 'z-10 group-hover/marker:scale-125'}
                      `}></div>
                      {/* Label on Hover */}
                      <div className={`
                        absolute -top-8 left-1/2 -translate-x-1/2 whitespace-nowrap
                        bg-black/90 text-white text-[10px] font-bold px-2 py-1 rounded
                        opacity-0 group-hover/marker:opacity-100 transition-opacity pointer-events-none
                        border border-white/10
                      `}>
                        {vehicle.id}
                      </div>
                   </div>
                 )
               })}
           </div>

           {/* Map Overlay Controls - Fixed position inside container */}
           <div className="absolute top-6 left-6 z-10 flex flex-col gap-3 pointer-events-none">
              {/* Filter Controls */}
              <div className="bg-[#121212]/90 backdrop-blur-md p-1.5 rounded-xl border border-white/10 shadow-lg pointer-events-auto flex gap-1">
                  {['All', 'Active', 'Maintenance', 'Low Battery'].map((status) => (
                    <button
                      key={status}
                      onClick={() => setFilterStatus(status as any)}
                      className={`
                        px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all
                        ${filterStatus === status 
                          ? 'bg-brand-yellow text-black shadow-sm' 
                          : 'text-gray-400 hover:bg-white/5 hover:text-white'}
                      `}
                    >
                      {status}
                    </button>
                  ))}
              </div>

              <div className="bg-[#121212]/90 backdrop-blur-md px-4 py-2 rounded-lg border border-white/10 shadow-lg pointer-events-auto w-max">
                 <span className="text-xs font-bold text-gray-200 uppercase tracking-wider">Zone: Downtown-A</span>
              </div>
           </div>

           <div className="absolute bottom-6 right-6 z-10 flex flex-col gap-2 pointer-events-none">
              <button 
                onClick={() => handleZoom(0.5)}
                className="bg-[#121212] hover:bg-brand-yellow hover:text-black transition-colors text-white p-3 rounded-xl border border-white/10 shadow-lg pointer-events-auto active:scale-95"
              >
                 <Plus />
              </button>
              <button 
                 onClick={() => handleZoom(-0.5)}
                 className="bg-[#121212] hover:bg-brand-yellow hover:text-black transition-colors text-white p-3 rounded-xl border border-white/10 shadow-lg pointer-events-auto active:scale-95"
              >
                 <Minus />
              </button>
              <button 
                 onClick={handleReset}
                 className="bg-[#121212] hover:bg-brand-yellow hover:text-black transition-colors text-white p-3 rounded-xl border border-white/10 shadow-lg mt-2 pointer-events-auto active:scale-95"
                 title="Reset View"
              >
                 <Crosshair size={20} />
              </button>
           </div>
       </div>

       {/* Sidebar Details Panel */}
       <div className="w-full lg:w-80 flex flex-col gap-4">
          <GlassCard className="flex-1 p-0 flex flex-col">
             <div className="p-6 border-b border-white/5">
                <h3 className="font-display font-bold text-white text-lg">Unit Details</h3>
             </div>

             {selectedVehicle ? (
               <div className="p-6 space-y-6 flex-1">
                  <div className="flex items-center justify-between">
                     <div className="w-16 h-16 rounded-2xl bg-[#1A1A1A] flex items-center justify-center text-brand-yellow border border-white/5">
                        <Navigation size={32} />
                     </div>
                     <div className="text-right">
                        <div className="text-2xl font-display font-bold text-white">{selectedVehicle.id}</div>
                        <StatusBadge status={selectedVehicle.status} />
                     </div>
                  </div>

                  <div className="space-y-4">
                     <div>
                        <div className="flex justify-between text-xs text-gray-500 font-bold uppercase mb-2">Battery Level</div>
                        <div className="h-2 bg-[#222] rounded-full overflow-hidden">
                           <div className={`h-full ${selectedVehicle.battery < 20 ? 'bg-red-500' : 'bg-green-500'} transition-all duration-1000`} style={{width: `${selectedVehicle.battery}%`}}></div>
                        </div>
                        <div className="text-right text-xs font-mono text-gray-400 mt-1">{selectedVehicle.battery}% Charged</div>
                     </div>

                     <div className="grid grid-cols-2 gap-3">
                        <div className="bg-[#1A1A1A] p-3 rounded-xl border border-white/5">
                           <div className="text-xs text-gray-500 font-bold uppercase">Speed</div>
                           <div className="text-lg font-mono text-white">{selectedVehicle.status === 'Active' ? '12-15' : '0'} km/h</div>
                        </div>
