export const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  let colorClass = 'bg-gray-800 text-gray-400 border-gray-700';
  if (status === 'Active' || status === 'Resolved' || status === 'Open') colorClass = 'bg-brand-yellow/10 text-brand-yellow border-brand-yellow/30 shadow-[0_0_10px_rgba(254,218,10,0.1)]';
  if (status === 'Maintenance' || status === 'In Progress') colorClass = 'bg-orange-500/10 text-orange-400 border-orange-500/30';
  if (status === 'Critical' || status === 'Low Battery') colorClass = 'bg-red-500/10 text-red-500 border-red-500/30';

  return (
    <span className={`px-3 py-1 rounded-lg text-[10px] uppercase font-bold tracking-wider backdrop-blur-md border ${colorClass}`}>
      {status}
    </span>
  );
};

