                    hoverGlow = 'group-hover/marker:shadow-[0_0_25px_#ef4444]';
                 }

                 return (
                   <div 
                     key={vehicle.id}
                     onClick={(e) => { e.stopPropagation(); setSelectedId(vehicle.id); }}
                     className="absolute cursor-pointer group/marker z-10"
                     style={{ 
                         top: `${vehicle.location[0]}%`, 
                         left: `${vehicle.location[1]}%`,
                         transition: 'top 2s linear, left 2s linear' // Smooth movement between updates
                     }}
                   >
                      <div className={`
                         w-4 h-4 rounded-full border-2 border-[#121212] ${statusColor} ${statusGlow} ${hoverGlow}
                         transition-all duration-300
                         ${isSelected ? 'scale-150 ring-4 ring-white/20 z-20' : 'z-10 group-hover/marker:scale-125'}
                      `}></div>
                      {/* Label on Hover */}
                      <div className={`
                        absolute -top-8 left-1/2 -translate-x-1/2 whitespace-nowrap
                        bg-black/80 backdrop-blur-md text-white text-[10px] font-bold px-2 py-1 rounded
                        opacity-0 group-hover/marker:opacity-100 transition-opacity pointer-events-none
                        border border-white/20 shadow-lg
                      `}>
                        {vehicle.id}
                      </div>
                   </div>
                 )
               })}
           </div>

           {/* Map Overlay Controls - Fixed position inside container */}
           <div className="absolute top-6 left-6 z-10 flex flex-col gap-3 pointer-events-none">
              {/* Filter Controls */}
              <div className="bg-[#121212]/80 backdrop-blur-xl p-1.5 rounded-xl border border-white/10 shadow-lg pointer-events-auto flex gap-1">
                  {['All', 'Active', 'Maintenance', 'Low Battery'].map((status) => (
                    <button
                      key={status}
                      onClick={(e) => { e.stopPropagation(); setFilterStatus(status as any); }}
                      className={`
                        px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-all
                        ${filterStatus === status 
                          ? 'bg-brand-yellow text-black shadow-[0_0_10px_rgba(254,218,10,0.3)]' 
                          : 'text-gray-400 hover:bg-white/5 hover:text-white'}
                      `}
                    >
                      {status}
                    </button>
                  ))}
              </div>

              <div className="bg-[#121212]/80 backdrop-blur-xl px-4 py-2 rounded-lg border border-white/10 shadow-lg pointer-events-auto w-max">
                 <span className="text-xs font-bold text-gray-200 uppercase tracking-wider">Zone: Downtown-A</span>
              </div>
           </div>

           <div className="absolute bottom-6 right-6 z-10 flex flex-col gap-2 pointer-events-none">
              <button 
                onClick={(e) => { e.stopPropagation(); handleZoom(0.5); }}
                className="bg-[#121212]/80 backdrop-blur-md hover:bg-brand-yellow hover:text-black transition-colors text-white p-3 rounded-xl border border-white/10 shadow-lg pointer-events-auto active:scale-95"
              >
                 <Plus />
              </button>
              <button 
                 onClick={(e) => { e.stopPropagation(); handleZoom(-0.5); }}
                 className="bg-[#121212]/80 backdrop-blur-md hover:bg-brand-yellow hover:text-black transition-colors text-white p-3 rounded-xl border border-white/10 shadow-lg pointer-events-auto active:scale-95"
              >
                 <Minus />
              </button>
              <button 
                 onClick={(e) => { e.stopPropagation(); handleReset(); }}
                 className="bg-[#121212]/80 backdrop-blur-md hover:bg-brand-yellow hover:text-black transition-colors text-white p-3 rounded-xl border border-white/10 shadow-lg mt-2 pointer-events-auto active:scale-95"
                 title="Reset View"
              >
                 <Crosshair size={20} />
              </button>
           </div>
       </div>

       {/* Sidebar Details Panel */}
       <div className="w-full lg:w-80 flex flex-col gap-4">
          <GlassCard className="flex-1 p-0 flex flex-col">
             <div className="p-6 border-b border-white/5 flex items-center justify-between relative z-10">
