  Bell, 
  Search, 
  Menu, 
  X, 
  LogOut, 
  Settings, 
  ChevronRight, 
  MessageSquare, 
  Send,
  Command
} from 'lucide-react';

type ViewState = 'auth' | 'onboarding' | 'dashboard';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('auth');
  const [user, setUser] = useState<User | null>(null);

