       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <GlassCard title="Support Tickets">
             <div className="space-y-4">
                {MOCK_TICKETS.map(ticket => (
                   <div key={ticket.id} className="p-4 bg-white/[0.03] rounded-xl border border-white/[0.05] flex justify-between items-center backdrop-blur-sm">
                      <div>
                         <div className="text-sm font-bold text-white mb-1">{ticket.title}</div>
                         <div className="text-xs text-gray-500">{ticket.id} • {ticket.created}</div>
                      </div>
                      <StatusBadge status={ticket.status} />
                   </div>
                ))}
             </div>
          </GlassCard>
          <GlassCard title="Knowledge Base Access">
             <div className="p-8 text-center text-gray-500">
                <Download size={48} className="mx-auto mb-4 opacity-50" />
                <p>Select a category to view documentation</p>
             </div>
          </GlassCard>
       </div>
    </div>
  );
};
